   145→Replace the props interface (lines 8-27 in current file) with:
   146→
   147→```tsx
   148→interface AssetCardProps {
   149→  asset: Asset;
   150→  selected: boolean;
   151→  onClick: () => void;
   152→  /**
   153→   * Optional double-click handler. Wired to the native `onDoubleClick`
   154→   * event AND to the `Enter` keyboard activation on the focused card.
   155→   * Omitting it preserves the pre-Plan-21 behavior: `Enter` falls back
   156→   * to `onClick`, and mouse dblclick is a no-op (the two preceding
   157→   * clicks still fire `onClick`).
   158→   */
   159→  onDoubleClick?: () => void;
   160→  showFavorite: boolean;
   161→  /**
   162→   * T2: the kebab (⋮) is always visible (no hover required) so touch
   163→   * devices can open the row context menu without long-press. Optional
