   182→  asset,
   183→  selected,
   184→  onClick,
   185→  onDoubleClick,
   186→  showFavorite,
   187→  onKebab,
   188→  multiSelected = false,
   189→  onToggleMultiSelect,
   190→}: AssetCardProps) {
   191→```
   192→
   193→Replace the `onKeyDown` function (lines 60-66) with:
   194→
   195→```tsx
   196→function onKeyDown(e: KeyboardEvent<HTMLDivElement>) {
   197→  if (e.target !== e.currentTarget) return;
   198→  if (e.key === 'Enter') {
   199→    e.preventDefault();
   200→    // Enter mirrors mouse double-click: open the preview if a handler
   201→    // is provided, otherwise fall back to the single-click action.
   202→    if (onDoubleClick) onDoubleClick();
   203→    else onClick();
   204→  } else if (e.key === ' ') {
   205→    e.preventDefault();
   206→    onClick();
   207→  }
   208→}
   209→```
