   217→  data-anim="card"
   218→  className={`${styles.card} ${selected ? styles.selected : ''} ${hasCheckbox ? styles.hasCheckbox : ''}`}
   219→  onClick={onClick}
   220→  onDoubleClick={onDoubleClick}
   221→  onKeyDown={onKeyDown}
   222→  aria-pressed={selected}
   223→  aria-label={`${asset.name}，${formatSize(asset.size)}`}
