            {multiSelected && <IconCheck size={12} aria-hidden="true" />}
          </button>
        )}
        {showFavorite && asset.favorite && (
          <span className={styles.favIcon} aria-label="已收藏">
            <IconStarFilled size={11} aria-hidden="true" />
          </span>
        )}
        {onKebab && (
          <span
            className={styles.kebabWrap}
            onClick={(e) => {
