                e.stopPropagation();
                onKebab(e);
              }}
            >
              <IconDotsVertical size={14} aria-hidden="true" />
            </button>
          </span>
        )}
      </div>
      <div className={styles.meta}>
        <div className={styles.name} title={asset.name}>
          {asset.name}
