    const user = userEvent.setup();
    const onClick = vi.fn();
    render(<AssetListRow {...makeProps({ onClick })} />);
    const select = screen.getByRole('button', { name: /选择 row\.png/ });
    select.focus();
    await user.keyboard('{Enter}');
    expect(onClick).toHaveBeenCalledTimes(1);
  });

