import { createAssetGridStagger } from '../src/lib/animations/asset-grid.js';

const A: Asset = {
  id: 'a',
  orgId: 'org-1',
  name: 'a.png',
  type: 'image',
  format: 'PNG',
  size: 1000,
  uploadedAt: '2026-06-07T00:00:00.000Z',
  uploadedBy: 'u1',
  tags: [],
  favorite: false,
  deletedAt: null,
  width: 100,
  height: 100,
};
const B: Asset = { ...A, id: 'b' };
const C: Asset = { ...A, id: 'c' };
const D: Asset = { ...A, id: 'd' };

describe('AssetGrid card stagger replay (T16)', () => {
  let originalMatchMedia: typeof window.matchMedia;

  beforeEach(() => {
    vi.clearAllMocks();
    originalMatchMedia = window.matchMedia;
    window.matchMedia = vi.fn().mockImplementation((q: string) => ({
      matches: true,
      media: q,
      onchange: null,
      addListener: vi.fn(),
      removeListener: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      dispatchEvent: vi.fn(() => false),
    }));
  });

  afterEach(() => {
    window.matchMedia = originalMatchMedia;
  });

  it('does not fire on first mount (the AppShell mount already animated the initial cards)', () => {
    const { rerender } = render(
      <AssetGrid
        assets={[]}
        selectedId={null}
        onSelect={() => {}}
        showFavorites={false}
      />,
    );
    expect(createAssetGridStagger).not.toHaveBeenCalled();

    // First non-empty render — still gated out by useIsFirstMount.
    rerender(
      <AssetGrid
        assets={[A, B]}
        selectedId={null}
        onSelect={() => {}}
        showFavorites={false}
      />,
    );
    expect(createAssetGridStagger).not.toHaveBeenCalled();
  });

  it('fires on the second non-empty assets change (the gate has flipped)', () => {
    const { rerender } = render(
      <AssetGrid
        assets={[]}
        selectedId={null}
        onSelect={() => {}}
        showFavorites={false}
      />,
    );
    rerender(
      <AssetGrid
        assets={[A, B]}
        selectedId={null}
        onSelect={() => {}}
        showFavorites={false}
      />,
    );
    expect(createAssetGridStagger).not.toHaveBeenCalled();

    // Second non-empty change — now the gate is open.
    rerender(
      <AssetGrid
        assets={[C, D]}
        selectedId={null}
        onSelect={() => {}}
        showFavorites={false}
      />,
    );
    expect(createAssetGridStagger).toHaveBeenCalledTimes(1);
    expect(createAssetGridStagger).toHaveBeenCalledWith(
      expect.any(HTMLElement),
      [expect.any(HTMLElement), expect.any(HTMLElement)],
    );
  });
});

import { screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { StoreProvider } from '../src/state/store';

const forwardAsset: Asset = {
  ...A,
  id: 'f01',
  name: 'forward.png',
};

function renderWithStore(ui: React.ReactElement) {
  return render(<StoreProvider>{ui}</StoreProvider>);
}

describe('AssetGrid onOpen forwarding (P21)', () => {
  it('passes onOpen down to each AssetCard; mouse dblclick triggers it with the asset id', async () => {
    const user = userEvent.setup();
    const onOpen = vi.fn();
    renderWithStore(
      <AssetGrid
        assets={[forwardAsset]}
        selectedId={null}
        onSelect={vi.fn()}
        showFavorites={false}
        onOpen={onOpen}
      />,
    );
    const card = screen.getByRole('button', { name: /forward\.png/ });
    await user.dblClick(card);
    expect(onOpen).toHaveBeenCalledWith('f01');
  });

  it('omitting onOpen does not throw on dblclick (backward compat for callers without it)', async () => {
    const user = userEvent.setup();
    renderWithStore(
      <AssetGrid
        assets={[forwardAsset]}
        selectedId={null}
        onSelect={vi.fn()}
        showFavorites={false}
      />,
    );
    const card = screen.getByRole('button', { name: /forward\.png/ });
    await expect(user.dblClick(card)).resolves.not.toThrow();
  });
});

